#include <iostream>
#include <vector>
using namespace std;

int count_inversions(const vector<int>& arr) {
    int inv_count = 0;
    for (int i = 0; i < arr.size(); ++i) {
        for (int j = i + 1; j < arr.size(); ++j) {
            if (arr[i] > arr[j]) {
                inv_count++;
            }
        }
    }
    return inv_count;
}

int main() {
    int n;
    while (cin >> n) {
        vector<int> first_grid, second_grid;
        for (int i = 0; i < n; ++i) {
            int x;
            for (int j = 0; j < n; ++j) {
                cin >> x;
                first_grid.push_back(x);
            }
        }
        for (int i = 0; i < n; ++i) {
            int x;
            for (int j = 0; j < n; ++j) {
                cin >> x;
                second_grid.push_back(x);
            }
        }

        // Remove zeroes (empty space)
        first_grid.erase(remove(first_grid.begin(), first_grid.end(), 0), first_grid.end());
        second_grid.erase(remove(second_grid.begin(), second_grid.end(), 0), second_grid.end());

        // Count inversions
        int inv_count1 = count_inversions(first_grid);
        int inv_count2 = count_inversions(second_grid);

        if (inv_count1 == inv_count2) {
            cout << "TAK" << endl;
        } else {
            cout << "NIE" << endl;
        }
    }

    return 0;
}
